38	// ExistingPath returns the DDx state root for projectRoot only when it already
39	// exists. Unlike Path, it never bootstraps a convention root.
40	func ExistingPath(ctx context.Context, projectRoot string) (string, bool) {
41		inTree := InTree(projectRoot)
42		if info, err := os.Stat(filepath.Join(inTree, "config.yaml")); err == nil && !info.IsDir() {
43			return inTree, true
44		}
45		root := filepath.Join(projectsRoot(), projectIdentity(ctx, projectRoot))
46		if info, err := os.Stat(root); err == nil && info.IsDir() {
47			return root, true
48		}
49		return "", false
50	}
