70	// Path returns the DDx state root for projectRoot.
71	//
72	// When the project already has an initialized in-tree `.ddx/config.yaml`,
73	// that remains authoritative. Otherwise DDx falls back to an XDG-scoped
74	// convention root derived from the project's canonical git remote, or a
75	// deterministic local identity.
76	func Path(ctx context.Context, projectRoot string) string {
77		inTree := InTree(projectRoot)
78		if info, err := os.Stat(filepath.Join(inTree, "config.yaml")); err == nil && !info.IsDir() {
79			return inTree
80		}
81		root := filepath.Join(projectsRoot(), projectIdentity(ctx, projectRoot))
82		_ = bootstrapConventionRoot(ctx, projectRoot, root)
83		return root
84	}
85	
86	func projectsRoot() string {
87		return filepath.Join(xdgDataHome(), "ddx", "projects")
88	}
89	
90	// GlobalDir returns the DDx global state root: ${XDG_DATA_HOME}/ddx/global.
91	func GlobalDir() string {
92		return filepath.Join(xdgDataHome(), "ddx", "global")
93	}
