95	func xdgDataHome() string {
96		if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
97			return xdg
98		}
99		home, err := os.UserHomeDir()
100		if err != nil {
101			return filepath.Join(os.TempDir(), "ddx-xdg")
102		}
103		return filepath.Join(home, ".local", "share")
104	}
