106	func LoadWorktreeRegistry(ctx context.Context, projectRoot string) (WorktreeRegistry, error) {
107		root := Path(ctx, projectRoot)
108		return readWorktreeRegistry(filepath.Join(root, "worktrees.json"))
109	}
