111	func SetMasterWorktree(ctx context.Context, projectRoot, masterPath string) error {
112		if ctx == nil {
113			ctx = context.Background()
114		}
115	
116		root := Path(ctx, projectRoot)
117		return withBootstrapLock(root, func() error {
118			registryPath := filepath.Join(root, "worktrees.json")
119			registry, err := readWorktreeRegistry(registryPath)
120			if err != nil {
121				return err
122			}
123	
124			canonicalPath, err := canonicalWorktreePath(masterPath)
125			if err != nil {
126				return err
127			}
128	
129			now := time.Now().UTC().Format(time.RFC3339Nano)
130			hostname, err := os.Hostname()
131			if err != nil || strings.TrimSpace(hostname) == "" {
132				hostname = "unknown"
133			}
134	
135			changed := upsertWorktreeRegistryEntry(&registry, canonicalPath, now, hostname)
136			if registry.Master != canonicalPath {
137				registry.Master = canonicalPath
138				changed = true
139			}
140			if !changed {
141				return nil
142			}
143			return writeWorktreeRegistry(registryPath, registry)
144		})
145	}
146	
147	func projectIdentity(ctx context.Context, projectRoot string) string {
148		return projectIdentityFromRemote(projectRoot, resolveOriginURL(ctx, projectRoot))
149	}
150	
151	func projectIdentityFromRemote(projectRoot, remoteURL string) string {
152		if remoteProject, ok := parseRemoteProject(remoteURL); ok {
153			return remoteProject
154		}
155		return localProjectIdentity(projectRoot)
156	}
157	
158	func resolveOriginURL(ctx context.Context, projectRoot string) string {
159		if ctx == nil {
160			ctx = context.Background()
161		}
162		out, err := gitpkg.Command(ctx, projectRoot, "remote", "get-url", "origin").Output()
163		if err != nil {
164			return ""
165		}
166		return strings.TrimSpace(string(out))
167	}
168	
169	func parseRemoteProject(remoteURL string) (string, bool) {
170		remoteURL = strings.TrimSpace(remoteURL)
171		if remoteURL == "" {
172			return "", false
173		}
174		if host, repoPath, ok := parseSCPLikeRemote(remoteURL); ok {
175			return filepath.Join(host, repoPath), true
176		}
177		u, err := url.Parse(remoteURL)
178		if err != nil || u.Host == "" {
179			return "", false
180		}
181		repoPath := normalizeRepoPath(u.Path)
182		if repoPath == "" {
183			return "", false
184		}
185		return filepath.Join(u.Host, repoPath), true
186	}
187	
188	func parseSCPLikeRemote(remoteURL string) (host, repoPath string, ok bool) {
189		if strings.Contains(remoteURL, "://") {
190			return "", "", false
191		}
192		at := strings.IndexByte(remoteURL, '@')
193		colon := strings.IndexByte(remoteURL, ':')
194		if at <= 0 || colon <= at+1 {
195			return "", "", false
196		}
197		host = strings.TrimSpace(remoteURL[at+1 : colon])
198		repoPath = normalizeRepoPath(remoteURL[colon+1:])
199		if host == "" || repoPath == "" {
200			return "", "", false
201		}
202		return host, repoPath, true
203	}
204	
205	func normalizeRepoPath(raw string) string {
206		raw = strings.TrimSpace(raw)
207		raw = strings.Trim(raw, "/")
208		raw = strings.TrimSuffix(raw, ".git")
209		if raw == "" {
210			return ""
211		}
212		parts := strings.FieldsFunc(raw, func(r rune) bool {
213			return r == '/' || r == '\\'
214		})
215		if len(parts) == 0 {
216			return ""
217		}
218		return filepath.Join(parts...)
219	}
220	
221	func localProjectIdentity(projectRoot string) string {
222		absRoot, err := filepath.Abs(projectRoot)
223		if err != nil {
224			absRoot = filepath.Clean(projectRoot)
225		}
226		base := filepath.Base(absRoot)
227		if base == "." || base == string(filepath.Separator) || base == "" {
228			base = "project"
229		}
230		return filepath.Join("local", base+"-"+shortPathHash(absRoot))
231	}
232	
233	func shortPathHash(path string) string {
234		sum := sha1.Sum([]byte(path))
235		return hex.EncodeToString(sum[:])[:8]
236	}
