1	package registry
2	
3	import (
4		"fmt"
5		"strings"
6	)
7	
8	// PackageType represents the type of a registry package.
9	type PackageType string
10	
11	const (
12		PackageTypeWorkflow     PackageType = "workflow"
13		PackageTypePlugin       PackageType = "plugin"
14		PackageTypePersonaPack  PackageType = "persona-pack"
15		PackageTypeTemplatePack PackageType = "template-pack"
16		PackageTypeResource     PackageType = "resource"
17	)
18	
19	// InstallMapping describes a source→target copy during installation.
20	type InstallMapping struct {
21		Source string `yaml:"source"`
22		Target string `yaml:"target"`
23	}
24	
25	// PackageInstall describes what to copy during installation.
26	type PackageInstall struct {
27		Root       *InstallMapping  `yaml:"root,omitempty"`       // plugin root (e.g., .ddx/plugins/helix)
28		Skills     []InstallMapping `yaml:"skills,omitempty"`     // skills directories (copied to each target)
29		Scripts    *InstallMapping  `yaml:"scripts,omitempty"`    // scripts/binaries
30		Symlinks   []SymlinkMapping `yaml:"symlinks,omitempty"`   // post-install symlinks
31		Executable []string         `yaml:"executable,omitempty"` // paths (relative to root) that must be executable
32	}
33	
34	// SymlinkMapping describes a symlink to create during installation.
35	type SymlinkMapping struct {
36		Source string `yaml:"source"` // the source path (relative to install root)
37		Target string `yaml:"target"` // the target path (where symlink points)
38	}
39	
40	// Package describes a single installable package.
41	type Package struct {
42		Name        string         `yaml:"name"`
43		Version     string         `yaml:"version"`
44		Description string         `yaml:"description"`
45		Type        PackageType    `yaml:"type"`
46		Source      string         `yaml:"source"`
47		APIVersion  string         `yaml:"api_version,omitempty"`
48		Install     PackageInstall `yaml:"install"`
49		Keywords    []string       `yaml:"keywords,omitempty"`
50		// Extra captures top-level keys not recognized by this DDx version so
51		// newer manifests can keep their unknown fields in memory without
52		// silently dropping them. See SD-018 "Manifest Versioning". Not
53		// marshaled via `yaml:"-"` so callers must preserve it explicitly.
54		Extra map[string]any `yaml:"-"`
55	}
56	
57	// Registry holds the list of known packages.
58	type Registry struct {
59		Packages []Package
60	}
61	
62	// BuiltinRegistry returns the built-in registry of known packages.
63	func BuiltinRegistry() *Registry {
64		return &Registry{
65			Packages: []Package{
66				{
67					Name:        "ddx",
68					Version:     "0.4.7",
69					Description: "DDx default library: prompts, personas, MCP configs, environments, skills",
70					Type:        PackageTypePlugin,
71					Source:      "https://github.com/DocumentDrivenDX/ddx",
72					Install: PackageInstall{
73						Root: &InstallMapping{
74							Source: "library",
75							Target: ".ddx/plugins/ddx",
76						},
77						Skills: []InstallMapping{
78							{Source: ".agents/skills/", Target: ".agents/skills/"},
79							{Source: ".agents/skills/", Target: ".claude/skills/"},
80						},
81					},
82					Keywords: []string{"library", "prompts", "personas", "mcp", "default", "skills"},
83				},
84				{
85					Name:        "helix",
86					Version:     "0.3.2",
87					Description: "Supervisory autopilot for AI-assisted software delivery",
88					Type:        PackageTypeWorkflow,
89					Source:      "https://github.com/DocumentDrivenDX/helix",
90					Install: PackageInstall{
91						// Plugin installs are project-local (FEAT-015): the tree
92						// lives under .ddx/plugins/<name>/, never in $HOME.
93						Root: &InstallMapping{
94							Source: ".",
95							Target: ".ddx/plugins/helix",
96						},
97						// Skills installed to project-local skill directories.
98						// skills.Install copies real files into both .agents/skills/
99						// and .claude/skills/ regardless of mapping target.
100						Skills: []InstallMapping{
101							{Source: ".agents/skills/", Target: ".agents/skills/"},
102							{Source: ".agents/skills/", Target: ".claude/skills/"},
103						},
104					},
105					Keywords: []string{"workflow", "methodology", "ai", "development"},
106				},
107			},
108		}
109	}
110	
111	// Find returns the package with the given name, or an error if not found.
112	func (r *Registry) Find(name string) (*Package, error) {
113		for i := range r.Packages {
114			if r.Packages[i].Name == name {
115				return &r.Packages[i], nil
116			}
117		}
118		return nil, fmt.Errorf("package %q not found in registry", name)
119	}
120	
121	// Search returns all packages whose name, description, or keywords contain the query.
122	func (r *Registry) Search(query string) []Package {
123		q := strings.ToLower(query)
124		var results []Package
125		for _, pkg := range r.Packages {
126			if matchesQuery(pkg, q) {
127				results = append(results, pkg)
128			}
129		}
130		return results
131	}
132	
133	func matchesQuery(pkg Package, query string) bool {
134		if strings.Contains(strings.ToLower(pkg.Name), query) {
135			return true
136		}
137		if strings.Contains(strings.ToLower(pkg.Description), query) {
138			return true
139		}
140		if strings.Contains(strings.ToLower(string(pkg.Type)), query) {
141			return true
142		}
143		for _, kw := range pkg.Keywords {
144			if strings.Contains(strings.ToLower(kw), query) {
145				return true
146			}
147		}
148		return false
149	}
150	
151	// IsResourcePath returns true if name looks like a resource path (e.g. "persona/foo").
152	func IsResourcePath(name string) bool {
153		return strings.Contains(name, "/")
154	}
