271	// InstallResource installs a single resource file (e.g. "persona/strict-code-reviewer")
272	// from the ddx-library GitHub repo into the local .ddx/plugins/ddx/<type>/ directory.
273	func InstallResource(resourcePath string) (InstalledEntry, error) {
274		entry := InstalledEntry{
275			Name:        resourcePath,
276			Version:     "latest",
277			Type:        PackageTypeResource,
278			Source:      "https://github.com/DocumentDrivenDX/ddx-library",
279			InstalledAt: time.Now(),
280		}
281	
282		// resourcePath is like "persona/strict-code-reviewer"
283		parts := strings.SplitN(resourcePath, "/", 2)
284		if len(parts) != 2 {
285			return entry, fmt.Errorf("invalid resource path %q: expected <type>/<name>", resourcePath)
286		}
287		resourceType, resourceName := parts[0], parts[1]
288	
289		// Determine target directory relative to cwd.
290		target := ddxroot.JoinRelative("plugins", "ddx", resourceType+"s")
291		if err := os.MkdirAll(target, 0755); err != nil {
292			return entry, fmt.Errorf("creating target directory %s: %w", target, err)
293		}
294	
295		// Fetch raw file from GitHub.
296		rawURL := fmt.Sprintf(
297			"https://raw.githubusercontent.com/easel/ddx-library/main/%ss/%s.md",
298			resourceType, resourceName,
299		)
300	
301		destFile := filepath.Join(target, resourceName+".md")
302		if err := downloadFile(rawURL, destFile); err != nil {
303			return entry, fmt.Errorf("downloading %s: %w", rawURL, err)
304		}
305	
306		entry.Files = append(entry.Files, destFile)
307		return entry, nil
308	}
