439	// copyMapping copies files from srcDir/<mapping.Source> to ExpandHome(mapping.Target).
440	// If the source is a single file and the target does not end with a path
441	// separator, the target is treated as the exact destination file path.
442	// If the source is a directory (or target ends with /), files are copied
443	// into the target directory.
444	// Returns the list of destination files written.
445	func copyMapping(srcDir string, mapping *InstallMapping) ([]string, error) {
446		src := filepath.Join(srcDir, filepath.FromSlash(mapping.Source))
447		dst := ExpandHome(mapping.Target)
448	
449		info, err := os.Stat(src)
450		if os.IsNotExist(err) {
451			// Source path doesn't exist in this repo — skip silently.
452			return nil, nil
453		}
454		if err != nil {
455			return nil, err
456		}
457	
458		var written []string
459	
460		if info.IsDir() {
461			// If dst is an existing symlink (e.g. from a prior --local install),
462			// remove it before creating the real directory.
463			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
464				if err := os.Remove(dst); err != nil {
465					return nil, fmt.Errorf("removing symlink at %s: %w", dst, err)
466				}
467			}
468	
469			// Copy directory tree into dst (create dst as a directory).
470			if err := os.MkdirAll(dst, 0755); err != nil {
471				return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
472			}
473	
474			// HELIX skills use symlinks, so resolve each entry via os.Stat.
475			entries, err := os.ReadDir(src)
476			if err != nil {
477				return nil, err
478			}
479			for _, e := range entries {
480				srcPath := filepath.Join(src, e.Name())
481				dstPath := filepath.Join(dst, e.Name())
482	
483				fi, err := os.Stat(srcPath)
484				if err != nil {
485					if recovered := recoverSkillDir(srcDir, src, e.Name()); recovered != "" {
486						srcPath = recovered
487						fi, err = os.Stat(srcPath)
488					}
489					if err != nil {
490						continue // skip unrecoverable broken symlinks
491					}
492				}
493	
494				if fi.IsDir() {
495					subFiles, subErr := copyMapping(srcPath, &InstallMapping{Source: ".", Target: dstPath})
496					if subErr != nil {
497						return nil, subErr
498					}
499					written = append(written, subFiles...)
500				} else if fi.Mode().IsRegular() {
501					if err := copyFile(srcPath, dstPath); err != nil {
502						return nil, err
503					}
504					written = append(written, dstPath)
505				}
506			}
507		} else {
508			// Source is a single file. If target ends with /, copy into that
509			// directory using the source filename; otherwise treat target as
510			// the exact destination file path.
511			var dstFile string
512			if strings.HasSuffix(mapping.Target, "/") {
513				if err := os.MkdirAll(dst, 0755); err != nil {
514					return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
515				}
516				dstFile = filepath.Join(dst, filepath.Base(src))
517			} else {
518				dstFile = dst
519			}
520			if err := copyFile(src, dstFile); err != nil {
521				return nil, err
522			}
523			written = append(written, dstFile)
524		}
525	
526		return written, nil
527	}
