529	// copyFile copies src to dst, creating parent directories as needed.
530	// Preserves the source file's permissions. If dst already exists (file,
531	// symlink, or directory), it is removed first.
532	func copyFile(src, dst string) error {
533		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
534			return err
535		}
536	
537		// Remove any existing file/symlink/directory at dst.
538		if _, err := os.Lstat(dst); err == nil {
539			if err := os.RemoveAll(dst); err != nil {
540				return fmt.Errorf("removing existing %s: %w", dst, err)
541			}
542		}
543	
544		srcInfo, err := os.Stat(src)
545		if err != nil {
546			return err
547		}
548	
549		in, err := os.Open(src)
550		if err != nil {
551			return err
552		}
553		defer func() { _ = in.Close() }()
554	
555		out, err := os.OpenFile(dst, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, srcInfo.Mode())
556		if err != nil {
557			return err
558		}
559		defer func() { _ = out.Close() }()
560	
561		_, err = io.Copy(out, in)
562		return err
563	}
564	
565	// downloadFile fetches url and writes it to dest.
566	func downloadFile(url, dest string) error {
567		resp, err := http.Get(url) //nolint:noctx
568		if err != nil {
569			return fmt.Errorf("fetching %s: %w", url, err)
570		}
571		defer func() { _ = resp.Body.Close() }()
572	
573		if resp.StatusCode != http.StatusOK {
574			return fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
575		}
576	
577		f, err := os.Create(dest)
578		if err != nil {
579			return err
580		}
581		defer func() { _ = f.Close() }()
582	
583		_, err = io.Copy(f, resp.Body)
584		return err
585	}
