587	// ExpandHome expands a leading ~ to the user's home directory.
588	func ExpandHome(path string) string {
589		if !strings.HasPrefix(path, "~") {
590			return path
591		}
592		home, err := os.UserHomeDir()
593		if err != nil {
594			return path
595		}
596		return filepath.Join(home, path[1:])
597	}
