247	// FEAT-015 invariants for project-local plugin installs:
248	//   - the plugin tree lives under <projectRoot>/.ddx/plugins/<name>/
249	//   - skill copies live under <projectRoot>/.agents/skills/ and .claude/skills/
250	//   - NO symlinks anywhere in the install output
251	//   - NO file resolves outside <projectRoot>
252	//
253	// The TestInstallSkills_* tests below replace the legacy TestSymlinkSkills_*
254	// tests deleted with symlinkSkills/pruneStaleSkillLinks.
255	
256	func walkAndAssertNoSymlinks(t *testing.T, root, projectRoot string) int {
257		t.Helper()
258		count := 0
259		absProject, _ := filepath.Abs(projectRoot)
260		require.NoError(t, filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
261			if err != nil {
262				if os.IsNotExist(err) {
263					return nil
264				}
265				return err
266			}
267			count++
268			if info.Mode()&os.ModeSymlink != 0 {
269				t.Errorf("FEAT-015: unexpected symlink at %s", path)
270			}
271			abs, absErr := filepath.Abs(path)
272			require.NoError(t, absErr)
273			rel, relErr := filepath.Rel(absProject, abs)
274			require.NoError(t, relErr)
275			if strings.HasPrefix(rel, "..") {
276				t.Errorf("FEAT-015: path %s escapes projectRoot %s", path, absProject)
277			}
278			return nil
279		}))
280		return count
281	}
